# ruff: noqa: E501
"""Bundled, dependency-free operator dashboard."""

DASHBOARD_HTML = r'''<!doctype html>
<html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1">
<title>Review operations</title><style>
:root{--ink:#172033;--muted:#667085;--line:#d7deea;--paper:#f3f6fb;--panel:#fff;--nav:#14243a;--blue:#246bfd;--red:#c63c4a;--amber:#a46107;--green:#16805c}*{box-sizing:border-box}body{margin:0;background:var(--paper);color:var(--ink);font:14px/1.45 Inter,ui-sans-serif,system-ui,sans-serif}button,input,select{font:inherit}.shell{display:grid;grid-template-columns:220px 1fr;min-height:100vh}aside{background:var(--nav);color:#dce8f7;padding:24px 16px;position:sticky;top:0;height:100vh}.brand{font:700 18px ui-monospace,monospace;letter-spacing:-.5px;margin:0 8px 28px}.brand small{display:block;color:#829bb8;font:600 10px system-ui;letter-spacing:1.7px;text-transform:uppercase;margin-top:4px}.nav{display:grid;gap:5px}.nav button{border:0;background:transparent;color:#aebfd4;text-align:left;padding:10px 12px;border-radius:6px;cursor:pointer}.nav button.active,.nav button:hover{background:#223a57;color:#fff}.pulse{position:absolute;bottom:24px;left:24px;font:11px ui-monospace;color:#8fa8c5}.pulse:before{content:'';display:inline-block;width:7px;height:7px;border-radius:50%;background:#4cd39a;margin-right:7px}main{padding:28px 34px;min-width:0}header{display:flex;align-items:flex-start;justify-content:space-between;margin-bottom:24px}h1{font:650 27px/1.1 Georgia,serif;margin:0 0 6px}header p{margin:0;color:var(--muted)}.refresh{background:var(--panel);border:1px solid var(--line);border-radius:6px;padding:8px 12px;cursor:pointer}.cards{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-bottom:22px}.card{background:var(--panel);border:1px solid var(--line);border-radius:8px;padding:15px}.card span{color:var(--muted);font-size:12px}.card strong{display:block;font:650 25px ui-monospace;margin-top:5px}.trace{background:#e8eef8;border:1px solid #cbd6e7;padding:12px 16px;border-radius:8px;margin-bottom:18px;color:#42516a;font:12px ui-monospace}.trace b{color:var(--blue)}.panel{background:var(--panel);border:1px solid var(--line);border-radius:8px;overflow:hidden}.toolbar{padding:12px;display:flex;gap:8px;border-bottom:1px solid var(--line);flex-wrap:wrap}.toolbar input,.toolbar select{border:1px solid var(--line);background:#fff;border-radius:5px;padding:7px 9px;min-width:145px}.toolbar button{border:0;background:var(--blue);color:#fff;border-radius:5px;padding:7px 13px;cursor:pointer}table{width:100%;border-collapse:collapse}th,td{text-align:left;padding:11px 13px;border-bottom:1px solid #e8ecf2;white-space:nowrap}th{font-size:10px;letter-spacing:.9px;text-transform:uppercase;color:var(--muted);background:#fafbfc}tbody tr{cursor:pointer}tbody tr:hover{background:#f4f7fc}.mono{font-family:ui-monospace,monospace}.status{font:700 10px ui-monospace;text-transform:uppercase;padding:3px 7px;border-radius:10px;background:#e8edf5}.status.failed,.status.error{background:#fde8ea;color:var(--red)}.status.running,.status.processing{background:#e3edff;color:#2459bb}.status.completed,.status.processed{background:#e2f5ed;color:var(--green)}.status.queued,.status.received{background:#fff1d9;color:var(--amber)}.empty,.error{padding:40px;text-align:center;color:var(--muted)}.error{color:var(--red)}dialog{border:0;border-radius:9px;padding:0;width:min(720px,92vw);box-shadow:0 24px 80px #07142666}dialog::backdrop{background:#0d1b2a99}.detail-head{padding:18px 21px;background:var(--nav);color:#fff;display:flex;justify-content:space-between}.detail-head button{border:0;background:transparent;color:#fff;font-size:20px;cursor:pointer}.detail-body{padding:20px;max-height:70vh;overflow:auto}.detail-body dl{display:grid;grid-template-columns:160px 1fr;gap:8px;margin:0}.detail-body dt{color:var(--muted)}.detail-body dd{margin:0;word-break:break-word}.detail-body pre{background:#eff3f8;padding:12px;overflow:auto;border-radius:5px;white-space:pre-wrap}.view{display:none}.view.active{display:block}.recent{display:grid;gap:8px}.failure{border-left:3px solid var(--red);padding:9px 12px;background:#fff7f7}.failure small{color:var(--muted)}a{color:var(--blue)}@media(max-width:850px){.shell{grid-template-columns:1fr}aside{position:relative;height:auto}.nav{grid-template-columns:repeat(4,1fr)}.pulse{display:none}main{padding:20px 14px}.cards{grid-template-columns:repeat(2,1fr)}table{display:block;overflow:auto}}@media(prefers-reduced-motion:no-preference){.view.active{animation:in .18s ease-out}@keyframes in{from{opacity:.5;transform:translateY(3px)}}}
</style></head><body><div class="shell"><aside><div class="brand">RO / OPS<small>review orchestrator</small></div><nav class="nav"><button data-view="overview" class="active">Overview</button><button data-view="events">Event inbox</button><button data-view="runs">Review runs</button><button data-view="tasks">Agent tasks</button></nav><div class="pulse">OPERATOR CHANNEL</div></aside><main><header><div><h1 id="title">System overview</h1><p id="subtitle">Review flow health and recent failures</p></div><button class="refresh" id="refresh">↻ Refresh</button></header>
<section id="overview" class="view active"><div class="cards" id="cards"></div><div class="trace"><b>TRACE RAIL</b> &nbsp; provider event → review run / agent task → pull request → pi-agent → publishing</div><div class="panel"><div class="toolbar"><strong>Recent failures</strong></div><div class="recent" id="failures"></div></div></section>
<section id="events" class="view"><div class="panel"><form class="toolbar" data-kind="events"><input name="repo_full_name" placeholder="Repository"><input name="delivery_id" placeholder="Delivery ID"><select name="status"><option value="">All statuses</option><option>received</option><option>queued</option><option>processed</option><option>failed</option></select><button>Apply filters</button></form><div id="events-table"></div></div></section>
<section id="runs" class="view"><div class="panel"><form class="toolbar" data-kind="runs"><input name="repo_full_name" placeholder="Repository"><select name="status"><option value="">All statuses</option><option>queued</option><option>running</option><option>completed</option><option>failed</option><option>cancelled</option></select><input name="stage" placeholder="Stage"><button>Apply filters</button></form><div id="runs-table"></div></div></section>
<section id="tasks" class="view"><div class="cards" id="queue"></div><div class="panel"><form class="toolbar" data-kind="tasks"><input name="repo_full_name" placeholder="Repository"><select name="status"><option value="">All statuses</option><option>queued</option><option>running</option><option>completed</option><option>failed</option><option>cancelled</option></select><input name="task_type" placeholder="Task type"><button>Apply filters</button></form><div id="tasks-table"></div></div></section></main></div>
<dialog id="detail"><div class="detail-head"><strong id="detail-title">Detail</strong><button aria-label="Close">×</button></div><div class="detail-body" id="detail-body"></div></dialog><script>
const API='/api/v1/observability';let current='overview',cache={};const cfg={events:{path:'provider-events',cols:[['created_at','Received'],['provider','Provider'],['repo_full_name','Repository'],['provider_event','Event'],['status','Status'],['delivery_id','Delivery']]},runs:{path:'review-runs',cols:[['created_at','Started'],['repo_full_name','Repository'],['pull_request_number','PR'],['stage','Stage'],['status','Status'],['operational_state.worker_state','Worker']]},tasks:{path:'agent-tasks',cols:[['created_at','Created'],['repo_full_name','Repository'],['pull_request_number','PR'],['source_author_login','Author'],['stage','Stage'],['status','Status'],['updated_at','Updated']]}};
const esc=v=>String(v??'—').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));const get=(o,p)=>p.split('.').reduce((v,k)=>v?.[k],o);const when=v=>v?new Date(v).toLocaleString():'—';
async function json(url){const r=await fetch(url,{headers:{Accept:'application/json'}});if(!r.ok)throw new Error(r.status===401||r.status===403?'Operator authentication required':`Request failed (${r.status})`);return r.json()}
function table(kind,data){cache[kind]=data.items;const c=cfg[kind].cols;let h='<table><thead><tr>'+c.map(x=>`<th>${x[1]}</th>`).join('')+'</tr></thead><tbody>';h+=data.items.map((x,i)=>'<tr data-row="'+i+'">'+c.map(([k])=>{let v=get(x,k);if(k.endsWith('_at'))v=when(v);if(k==='status')return `<td><span class="status ${esc(v)}">${esc(v)}</span></td>`;return `<td class="${k==='delivery_id'?'mono':''}">${esc(v)}</td>`}).join('')+'</tr>').join('');return data.items.length?h+'</tbody></table>':'<div class="empty">No records match these filters.</div>'}
async function load(kind,params=''){const el=document.querySelector('#'+kind+'-table');el.innerHTML='<div class="empty">Loading…</div>';try{const d=await json(`${API}/${cfg[kind].path}?limit=50&${params}`);el.innerHTML=table(kind,d);if(kind==='tasks')queue(d.queue);el.querySelectorAll('tr[data-row]').forEach(r=>r.onclick=()=>detail(kind,cache[kind][r.dataset.row].id))}catch(e){el.innerHTML=`<div class="error">${esc(e.message)}</div>`}}
function queue(q={}){document.querySelector('#queue').innerHTML=['queued','running','completed','failed','cancelled'].map(k=>`<div class="card"><span>${k}</span><strong>${esc(q[k]||0)}</strong></div>`).join('')}
async function overview(){try{const [e,r,t]=await Promise.all(Object.keys(cfg).map(k=>json(`${API}/${cfg[k].path}?limit=20`)));document.querySelector('#cards').innerHTML=[['Events',e.total],['Active runs',r.items.filter(x=>['queued','running'].includes(x.status)).length],['Queued tasks',t.queue.queued],['Failures',e.items.filter(x=>x.status==='failed').length+r.items.filter(x=>x.status==='failed').length+t.queue.failed]].map(x=>`<div class="card"><span>${x[0]}</span><strong>${x[1]}</strong></div>`).join('');const bad=[...e.items.filter(x=>x.error_message),...r.items.filter(x=>x.error||x.failure_code),...t.items.filter(x=>x.error_message)].sort((a,b)=>new Date(b.updated_at||b.created_at)-new Date(a.updated_at||a.created_at)).slice(0,8);document.querySelector('#failures').innerHTML=bad.length?bad.map(x=>`<div class="failure"><b>${esc(x.repo_full_name)} #${esc(x.pull_request_number)}</b><br>${esc(x.error_message||x.error||x.failure_code)}<br><small>${when(x.updated_at||x.created_at)}</small></div>`).join(''):'<div class="empty">No recent failures.</div>'}catch(e){document.querySelector('#cards').innerHTML=`<div class="error">${esc(e.message)}</div>`}}
async function detail(kind,id){const d=document.querySelector('#detail');document.querySelector('#detail-title').textContent=`${kind.slice(0,-1)} · ${id}`;document.querySelector('#detail-body').innerHTML='Loading…';d.showModal();try{const x=await json(`${API}/${cfg[kind].path}/${encodeURIComponent(id)}`);let links='';if(x.review_run_id)links+=`<a href="#" data-open="runs:${esc(x.review_run_id)}">Review run</a> · `;if(x.agent_task_id||x.agent_task?.id)links+=`<a href="#" data-open="tasks:${esc(x.agent_task_id||x.agent_task.id)}">Agent task</a> · `;if(x.agent_session_id)links+=`<a href="${API}/agent-sessions/${encodeURIComponent(x.agent_session_id)}" target="_blank">pi-agent status</a> · `;if(x.pull_request_context?.html_url)links+=`<a href="${esc(x.pull_request_context.html_url)}" target="_blank">Pull request</a>`;document.querySelector('#detail-body').innerHTML=(links?`<p>${links}</p>`:'')+'<dl>'+Object.entries(x).filter(([,v])=>typeof v!=='object'||v===null).map(([k,v])=>`<dt>${esc(k)}</dt><dd>${esc(v)}</dd>`).join('')+'</dl><h3>Structured detail</h3><pre>'+esc(JSON.stringify(x,null,2))+'</pre>';document.querySelectorAll('[data-open]').forEach(a=>a.onclick=e=>{e.preventDefault();const [k,i]=a.dataset.open.split(':');detail(k,i)})}catch(e){document.querySelector('#detail-body').innerHTML=`<div class="error">${esc(e.message)}</div>`}}
const titles={overview:['System overview','Review flow health and recent failures'],events:['Provider event inbox','Webhook intake, processing state and linked work'],runs:['Review runs','Execution, worker locks, timeouts and publishing'],tasks:['Agent task queue','Queue health and agent work results']};document.querySelectorAll('.nav button').forEach(b=>b.onclick=()=>{current=b.dataset.view;document.querySelectorAll('.nav button,.view').forEach(x=>x.classList.remove('active'));b.classList.add('active');document.querySelector('#'+current).classList.add('active');[document.querySelector('#title').textContent,document.querySelector('#subtitle').textContent]=titles[current];current==='overview'?overview():load(current)});document.querySelectorAll('form').forEach(f=>f.onsubmit=e=>{e.preventDefault();load(f.dataset.kind,new URLSearchParams([...new FormData(f)].filter(([,v])=>v)).toString())});document.querySelector('#refresh').onclick=()=>current==='overview'?overview():load(current);document.querySelector('#detail .detail-head button').onclick=()=>document.querySelector('#detail').close();overview();
</script></body></html>'''
